<?php
class VendorController extends Controller { public function index(): void { $cid=$this->companyId(); $stmt=$this->db->prepare('SELECT * FROM vendors WHERE company_id=? ORDER BY name'); $stmt->execute([$cid]); $vendors=$stmt->fetchAll(); $this->render('vendors/index', compact('vendors')); } public function save(): void { check_csrf(); $cid=$this->companyId(); $stmt=$this->db->prepare('INSERT INTO vendors(company_id,name,email,phone,address) VALUES(?,?,?,?,?)'); $stmt->execute([$cid,$_POST['name'],$_POST['email']??'',$_POST['phone']??'',$_POST['address']??'']); $this->redirect('vendors'); }}
